+            moisture.push(tile.moisture);
+            accent.push(tile.accent);
+            fertility.push(tile.fertility_bias);
+            temperature.push(tile.temperature_bias);
+            kinds.push(tile.kind);
+        }
+        Self {
+            dims,
+            cell_size: layer.cell_size(),
+            elevation,
+            moisture,
+            accent,
+            fertility,
+            temperature,
+            kinds,
+        }
+    }
